"""Thread-safe connection pool with health checking."""
import threading
import time
import random
from collections import deque
from typing import Optional


class Connection:
    """Simulated database connection."""
    _counter = 0
    _lock = threading.Lock()

    def __init__(self):
        with Connection._lock:
            Connection._counter += 1
            self.id = Connection._counter
        self.created_at = time.time()
        self.last_used = time.time()
        self._closed = False

    def execute(self, query: str) -> str:
        if self._closed:
            raise RuntimeError(f"Connection {self.id} is closed")
        time.sleep(random.uniform(0.001, 0.005))  # simulate work
        self.last_used = time.time()
        return f"result_{self.id}"

    def close(self):
        self._closed = True

    @property
    def is_healthy(self) -> bool:
        return not self._closed and (time.time() - self.created_at) < 30


class ConnectionPool:
    """Connection pool with min/max size and health checking.

    Usage:
        pool = ConnectionPool(min_size=2, max_size=10)
        conn = pool.acquire()
        try:
            conn.execute("SELECT 1")
        finally:
            pool.release(conn)
    """

    def __init__(self, min_size: int = 2, max_size: int = 10,
                 max_idle_time: float = 60.0):
        self.min_size = min_size
        self.max_size = max_size
        self.max_idle_time = max_idle_time

        self._pool = deque()  # available connections
        self._in_use = set()  # checked-out connections
        self._lock = threading.Lock()
        self._total_created = 0

        # Pre-fill minimum connections
        for _ in range(min_size):
            conn = self._create_connection()
            self._pool.append(conn)

    def _create_connection(self) -> Connection:
        self._total_created += 1
        return Connection()

    def acquire(self, timeout: float = 5.0) -> Connection:
        """Acquire a connection from the pool."""
        deadline = time.time() + timeout

        while time.time() < deadline:
            with self._lock:
                # Try to get an existing healthy connection
                while self._pool:
                    conn = self._pool.popleft()
                    if conn.is_healthy:
                        self._in_use.add(conn)
                        return conn
                    else:
                        conn.close()

                # No available connections — can we create a new one?
                current_total = len(self._pool) + len(self._in_use)
                if current_total < self.max_size:
                    conn = self._create_connection()
                    self._in_use.add(conn)
                    return conn

            # Pool exhausted, wait a bit
            time.sleep(0.01)

        raise TimeoutError("Could not acquire connection within timeout")

    def release(self, conn: Connection):
        """Return a connection to the pool."""
        # BUG: No lock here! Race condition with acquire()
        if conn in self._in_use:
            self._in_use.remove(conn)
            if conn.is_healthy:
                self._pool.append(conn)
            else:
                conn.close()

    @property
    def size(self) -> int:
        """Total connections (available + in use)."""
        with self._lock:
            return len(self._pool) + len(self._in_use)

    @property
    def available(self) -> int:
        """Number of available connections."""
        with self._lock:
            return len(self._pool)

    def health_check(self):
        """Remove unhealthy idle connections, maintain minimum pool size."""
        with self._lock:
            healthy = deque()
            for conn in self._pool:
                if conn.is_healthy and (time.time() - conn.last_used) < self.max_idle_time:
                    healthy.append(conn)
                else:
                    conn.close()
            self._pool = healthy

            # Ensure minimum connections
            while len(self._pool) + len(self._in_use) < self.min_size:
                self._pool.append(self._create_connection())

    def close_all(self):
        """Shut down the pool."""
        with self._lock:
            for conn in self._pool:
                conn.close()
            for conn in self._in_use:
                conn.close()
            self._pool.clear()
            self._in_use.clear()
